SELECT COUNT(*) FROM (
    SELECT log_date, SUM(calories) AS total
    FROM diet_log
    WHERE user_id = #{userId}
      AND log_date BETWEEN #{startDate} AND #{endDate}
    GROUP BY log_date
    HAVING total <= #{targetCalories}
) t

SELECT COUNT(*) FROM (
    SELECT log_date, SUM(calories) AS total
    FROM diet_log
    WHERE user_id = #{userId}
      AND log_date BETWEEN #{startDate} AND #{endDate}
    GROUP BY log_date
    HAVING total > #{targetCalories}
) t
